blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz <strong>Pytania alternatywne</strong> – pytania, które oferują wybór między opcjami za pomocą spójnika <strong>lub</strong>.",
    "rules": [
        {
            "label": "DWIE OPCJE",
            "color": "emerald",
            "text": "<strong>Wybór pomiędzy dwoma</strong> — połącz przez lub:",
            "example": "Czy wolisz kawę czy herbatę?"
        },
        {
            "label": "STRUKTURA",
            "color": "blue",
            "text": "<strong>Jako pytanie typu Tak/Nie</strong> + lub + opcja:",
            "example": "Czy jest czarna czy biały?"
        },
        {
            "label": "ODPOWIEDŹ",
            "color": "amber",
            "text": "<strong>Wybieramy opcję</strong>, nie odpowiadamy Tak/Nie:",
            "example": "Poproszę kawę. / Wolę herbatę."
        }
    ]
}

{
    "title": "1. Czym są pytania alternatywne?",
    "intro": "Pytania alternatywne to pytania wielokrotnego wyboru:",
    "items": [
        {
            "label": "Pytanie tak/nie",
            "title": "Czy lubisz kawę?",
            "subtitle": "Odpowiedź: Tak/Nie"
        },
        {
            "label": "Alternatywa",
            "title": "Czy lubisz kawę czy herbatę?",
            "subtitle": "Odpowiedź: Kawa/Herbata"
        },
        {
            "label": "Struktura",
            "title": "Pytanie + LUB + Alternatywa",
            "subtitle": "Pytanie + LUB + Alternatywa"
        }
    ]
}

{
    "title": "2. Podstawowa struktura pytań alternatywnych",
    "sections": [
        {
            "label": "Z rzeczownikami prostymi",
            "color": "emerald",
            "description": "Najprostszą formą jest wybór pomiędzy dwoma rzeczownikami:",
            "examples": [
                {
                    "en": "Wolisz kawę czy herbatę?",
                    "ua": "Jest nauczycielką czy lekarzem?"
                },
                {
                    "en": "Would you like meat or fish?",
                    "ua": "Ти б хотів мʼясо чи рибу?"
                },
                {
                    "en": "Is she a teacher or a doctor?",
                    "ua": "Jest nauczycielką czy lekarzem?"
                },
                {
                    "en": "Jesteś z Hiszpanii czy Włoch?",
                    "ua": "Jesteś z Hiszpanii lub Włoch Włochy?"
                }
            ]
        },
        {
            "label": "Z przymiotnikami",
            "color": "sky",
            "description": "Alternatywa między przymiotnikami – opisywanie czegoś:",
            "examples": [
                {
                    "en": "Czy to jest duże czy małe?",
                    "ua": "Jest duże czy małe? mały?"
                },
                {
                    "en": "Czy test jest łatwy czy trudny?",
                    "ua": "Test łatwy czy trudny?"
                },
                {
                    "en": "Jesteś szczęśliwy czy smutny?",
                    "ua": "Jesteś szczęśliwy czy smutny?"
                },
                {
                    "en": "Czy film był dobry czy źle?",
                    "ua": " źle?"
                }
            ]
        },
        {
            "label": "Struktura",
            "color": "purple",
            "description": "Ogólna alternatywna formuła pytania:",
            "examples": [
                {
                    "en": "Pomocniczy + Temat + Czasownik + Opcja A + LUB + Opcja B?",
                    "ua": "Pomocniczy + Temat + Czasownik + Opcja A + OR + Opcja B?"
                }
            ],
            "note": "📌 Struktura jak w pytaniu Tak/Nie, ale dodano OR + alternatywa"
        }
    ]
}

{
    "title": "3. Alternatywne pytania z DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "W czasie Present Simple używamy <strong>do/does</strong> + lub + alternatywa:",
            "examples": [
                {
                    "en": "Czy chodzisz lub jedziesz do pracy?",
                    "ua": "Czy ona lubi koty lub psy?"
                },
                {
                    "en": "Does she like cats or dogs?",
                    "ua": "Czy ona lubi koty czy psy?"
                },
                {
                    "en": "Czy mieszkają w domu czy w mieszkaniu?",
                    "ua": "Czy mieszkają w domu czy mieszkaniu?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "sky",
            "description": "W czasie Past Simple używamy <strong>did</strong> + lub + alternatywy:",
            "examples": [
                {
                    "en": "Czy jechałeś autobusem czy pociągiem?",
                    "ua": "Pojechałeś autobusem czy pociągiem?[[[CODX_4]]]Czy ona kupiła laptopa lub tablet?"
                },
                {
                    "en": "Did she buy a laptop or a tablet?",
                    "ua": "Czy kupiła laptopa czy tablet?"
                },
                {
                    "en": "Wygrała czy przegrała?",
                    "ua": "Wygrała czy przegrała?"
                }
            ]
        },
        {
            "label": "Z różnymi czasownikami",
            "color": "amber",
            "description": "Możesz zadawać pytania na temat różnych działania:",
            "examples": [
                {
                    "en": "Chcesz zostać czy odejść?",
                    "ua": "Chcesz zostać czy odejść?"
                },
                {
                    "en": "Dzwoniłeś do niego lub wysyłałeś SMS-y?",
                    "ua": "Dzwoniłeś do niego lub wysyłałeś SMS-y?"
                },
                {
                    "en": "Czy on pracuje lub uczy się? czasowniki, rzeczowniki, przymiotniki",
                    "ua": "Він працює чи навчається?"
                }
            ],
            "note": "📌 OR може зʼєднувати дієслова, іменники, прикметники"
        }
    ]
}

{
    "title": "4. Alternatywne pytania z TO BE",
    "sections": [
        {
            "label": "obecny — AM/IS/ARE",
            "color": "blue",
            "description": "Za pomocą czasownika <strong>być</strong> dokonujemy inwersji + lub:",
            "examples": [
                {
                    "en": "Jesteś uczniem czy nauczycielem?",
                    "ua": "Jesteś uczniem lub studentem nauczyciel?"
                },
                {
                    "en": "Czy na zewnątrz jest gorąco czy zimno?",
                    "ua": "Czy na zewnątrz jest gorąco czy zimno?"
                },
                {
                    "en": "Czy to Brytyjczycy czy Amerykanie?",
                    "ua": "To Brytyjczycy czy Amerykanie? <strong>była/była</strong>:"
                }
            ]
        },
        {
            "label": "Past — WAS/WERE",
            "color": "purple",
            "description": "У минулому часі з <strong>was/were</strong>:",
            "examples": [
                {
                    "en": "Czy książka była interesująca czy nudna?",
                    "ua": "Czy była szczęśliwa czy smutna?"
                },
                {
                    "en": "Byłeś w domu czy w pracy?",
                    "ua": ""
                },
                {
                    "en": "Was she happy or upset?",
                    "ua": "Czy była szczęśliwa czy smutna?"
                }
            ]
        },
        {
            "label": "Zaimkami TO/TAK",
            "color": "rose",
            "description": "Alternatywa przy identyfikowaniu obiektów:",
            "examples": [
                {
                    "en": "Czy to Twoja torba czy jej?",
                    "ua": "Czy to Twoja torba czy jej?"
                },
                {
                    "en": "Czy to kot czy pies? Alternatywne pytania z czasownikami modalnymi",
                    "ua": "То кіт чи собака?"
                },
                {
                    "en": "Are these apples or pears?",
                    "ua": "Це яблука чи груші?"
                }
            ],
            "note": "📌 Відповідь: обираємо один варіант, НЕ Yes/No"
        }
    ]
}

{
    "title": "5. Альтернативні питання з модальними дієсловами",
    "sections": [
        {
            "label": "CAN / COULD",
            "color": "emerald",
            "description": "Za pomocą <strong>can/could</strong>, aby wybrać możliwości lub umiejętności:",
            "examples": [
                {
                    "en": "Umiesz pływać lub nurkować?",
                    "ua": "Umiesz pływać lub nurkować?"
                },
                {
                    "en": "Czy moglibyśmy spotkać się dzisiaj lub jutro? pragnienie:",
                    "ua": "Ми могли б зустрітися сьогодні чи завтра?"
                },
                {
                    "en": "Can she speak French or German?",
                    "ua": "Вона розмовляє французькою чи німецькою?"
                }
            ]
        },
        {
            "label": "WILL / WOULD",
            "color": "sky",
            "description": "З <strong>will/would</strong> для майбутніх дій або бажань:",
            "examples": [
                {
                    "en": "Przyjedziesz samochodem czy autobusem?",
                    "ua": "Przyjedziesz rano czy po południu? napisz?"
                },
                {
                    "en": "Would you like wine or beer?",
                    "ua": "Ти б хотів вина чи пива?"
                },
                {
                    "en": "Will they arrive in the morning or evening?",
                    "ua": "Вони приїдуть вранці чи ввечері?"
                }
            ]
        },
        {
            "label": "SHOULD / MUST",
            "color": "amber",
            "description": "Для порад або обовʼязків з вибором:",
            "examples": [
                {
                    "en": "Should I call or text you?",
                    "ua": "Мені тобі телефонувати чи написати?"
                },
                {
                    "en": "Czy musimy płacić gotówką czy kartą?",
                    "ua": "Czy mamy płacić gotówką czy kartą?"
                }
            ],
            "note": "📌 Czasownik modalny + podmiot + czasownik + lub + alternatywa"
        }
    ]
}

{
    "title": "6. Bardziej złożone pytania alternatywne",
    "sections": [
        {
            "label": "Z frazami i zdaniami",
            "color": "purple",
            "description": "LUB można łączyć całe frazy lub zdania:",
            "examples": [
                {
                    "en": "Chcesz iść teraz, czy trochę poczekać?",
                    "ua": "Chcesz iść teraz, czy trochę poczekać?"
                },
                {
                    "en": "Możemy zjeść o godz. do domu czy do restauracji?",
                    "ua": "Zjemy w domu czy pójdziemy do restauracji?"
                },
                {
                    "en": "Będziesz uczyć się angielskiego lub innego języka?",
                    "ua": "Będziesz uczyć się angielskiego lub innego języka?"
                }
            ]
        },
        {
            "label": "Więcej niż dwa opcje",
            "color": "blue",
            "description": "Można zaoferować więcej niż dwie opcje:",
            "examples": [
                {
                    "en": "Czy wolisz czerwony, niebieski czy zielony?",
                    "ua": "Czy wolisz czerwony, niebieski czy zielony?"
                },
                {
                    "en": "Czy powinniśmy się spotkać w poniedziałek, wtorek czy Środa?",
                    "ua": "Czy powinniśmy się spotkać w poniedziałek, wtorek czy środę?"
                },
                {
                    "en": "Czy ona jest z Francji, Hiszpanii czy Włoch?",
                    "ua": "Czy ona jest z Francji, Hiszpanii czy Włoch?"
                }
            ]
        },
        {
            "label": "Ze słowami pytającymi",
            "color": "rose",
            "description": "Pytania alternatywne możesz zacząć od słów Wh:",
            "examples": [
                {
                    "en": "Co wolisz – kawę czy herbatę? herbata?",
                    "ua": "Що ти більше любиш — каву чи чай?"
                },
                {
                    "en": "Gdzie powinniśmy pójść — do parku czy na plażę?",
                    "ua": "Gdzie powinniśmy pójść — do parku czy na plażę?"
                },
                {
                    "en": "Kiedy przyjedziesz — dziś czy jutro?",
                    "ua": ""
                }
            ],
            "note": "📌 Który jest często używany do wyboru pomiędzy opcjami"
        }
    ]
}

{
    "title": "7. Jak odpowiedzieć na pytania alternatywne",
    "sections": [
        {
            "label": "Wybierz opcję",
            "color": "emerald",
            "description": "Odpowiedź to jedna z proponowanych opcji, a NIE Tak/Nie:",
            "examples": [
                {
                    "en": "P: Kawa czy herbata? — A: Poproszę kawę.",
                    "ua": "P: Kawa czy herbata? — A: Poproszę kawę."
                },
                {
                    "en": "P: Czy to jest czarne czy białe? — A: Jest czarny.",
                    "ua": "P: Jest czarny czy biały? — A: Jest czarny."
                },
                {
                    "en": "P: Chodzisz czy prowadzisz? — A: Zwykle prowadzę.",
                    "ua": "P: Chodzisz lub prowadzisz? — A: Zwykle to robię."
                }
            ]
        },
        {
            "label": "Odrzuć obie opcje",
            "color": "sky",
            "description": "Możesz odrzucić obie opcje i zaproponować trzecią:",
            "examples": [
                {
                    "en": "P: Kawa czy herbata? — O: Ani. Poproszę wodę.",
                    "ua": "P: Kawa czy herbata? — O: Ani jedno, ani drugie. Poproszę wodę."
                },
                {
                    "en": "P: Czy jesteś z Hiszpanii czy Włoch? — O: Ani. Jestem z Francji.",
                    "ua": "P: Jesteś z Hiszpanii czy Włoch? — A: Nie. Jestem z Francji."
                }
            ]
        },
        {
            "label": "Wybierz oba",
            "color": "amber",
            "description": "Czasami możesz wybrać oba:",
            "examples": [
                {
                    "en": "P: Czy lubisz koty czy psy? — O: Obydwa! Kocham zwierzęta.",
                    "ua": "P: Lubisz koty czy psy? — O: Obydwa! Kocham zwierzęta."
                },
                {
                    "en": "P: Kawa czy herbata? — A: Lubię jedno i drugie.",
                    "ua": "P: Kawa czy herbata? — O: Lubię oba."
                }
            ],
            "note": "📌 Ani — ani, Obydwa — oba"
        }
    ]
}

{
    "title": "8. Porównanie pytań typu „tak/nie” i pytań alternatywnych",
    "intro": "Główne różnice między tymi dwoma rodzajami pytań:",
    "rows": [
        {
            "en": "Pytanie tak/nie",
            "ua": "Pytanie ogólne",
            "note": "Czy lubisz kawę? → Tak/Nie"
        },
        {
            "en": "Pytanie alternatywne",
            "ua": "Pytanie alternatywne",
            "note": "Czy lubisz kawę czy herbatę? → Kawa/Herbata"
        },
        {
            "en": "Struktura",
            "ua": "Struktura",
            "note": "Dodatkowy + Temat + Czasownik + LUB + Alternatywa"
        },
        {
            "en": "Typ odpowiedzi",
            "ua": "Odpowiedź type",
            "note": "Wybierz jedną opcję, NIE Tak/Nie"
        },
        {
            "en": "Intonacja",
            "ua": "Intonacja",
            "note": "Opada na ostatnią opcję"
        }
    ],
    "warning": "📌 Główna różnica: <strong>LUB + alternatywa</strong>"
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Odpowiedź tak/nie zamiast wyboru opcji.",
            "wrong": "❌ P: Kawa czy herbata? O: Tak.",
            "right": "​​​​ <span class="font-mono">P: Kawa czy herbata? A: Poproszę kawę.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zła kolejność słów w pytaniu.",
            "wrong": "❌Wolisz kawę czy herbatę?",
            "right": " ✅ <span class="font-mono">Wolisz kawę czy herbatę? herbata?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zapomnij OR pomiędzy opcjami.",
            "wrong": "❌ Chcesz kawę, herbatę?",
            "right": "​​​​​​​​ pomocnicze."
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Неправильна форма дієслова після допоміжного.",
            "wrong": "❌ Czy ona lubisz koty czy psy?",
            "right": "​​​​ <span class="font-mono">Czy ona lubi koty czy psy?</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz poprawną formę alternatywnego pytania.",
    "selects": [
        {
            "label": "a) Wolisz kawę czy herbatę? / b) Wolisz kawę czy herbatę? / c) Czy wolisz kawę i herbatę?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Czy jest gorąco czy zimno? / b) Czy jest gorąco czy zimno? / c) Czy jest gorąco czy zimno?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Czy potrafisz pływać i nurkować? / b) Czy potrafisz pływać i nurkować? / c) Czy potrafisz pływać i nurkować? opcje.",
            "prompt": "Який варіант правильний?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Вправа 2. Постав альтернативне питання",
    "input_intro": "Утвори альтернативне питання з поданих варіантів.",
    "inputs": [
        {
            "before": "Lubi (koty/psy). → ",
            "after": ""
        },
        {
            "before": "Jesteś z (Hiszpania / Włochy). → ",
            "after": ""
        },
        {
            "before": "Przyjdą (dziś / jutro). → ",
            "after": ""
        },
        {
            "before": "Jest (duży/mały). →",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu alternatywnym.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Wolisz kawę czy herbatę?",
            "example_target": "Wolisz kawę czy herbata?"
        },
        {
            "original": "1. Czy ona lubi koty czy psy?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Czy jest gorąco i zimno?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Umiesz pływać lub nurkować?",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne tematy z działu Rodzaje zdań pytających",
    "items": [
        {
            "label": "Pytania tak/nie – pytania ogólne",
            "current": false
        },
        {
            "label": "Wh-pytania – specjalne pytania",
            "current": false
        },
        {
            "label": "Pytania alternatywne – pytania alternatywne (bieżące)",
            "current": true
        },
        {
            "label": "Pytania tematyczne",
            "current": false
        },
        {
            "label": "Question Tags — Розділові питання",
            "current": false
        }
    ]
}
